static int launch(const char *image) {
    for (const unsigned char *p = (const unsigned char *)image; *p; ++p) {
        if (!((*p >= 'a' && *p <= 'z') ||
              (*p >= 'A' && *p <= 'Z') ||
              (*p >= '0' && *p <= '9') ||
              *p == '.' || *p == '_' || *p == '-' || *p == '/')) {
            fprintf(stderr, "Invalid image name\n");
            return 1;
        }
    }

    char command[512];
    snprintf(command, sizeof(command), "convert %s -resize 200x200 thumb.png", image);

    return system(command);
}
